from __future__ import annotations

from dataclasses import dataclass, replace
from decimal import Decimal, InvalidOperation
from typing import Protocol, TypeAlias


MoneyInput: TypeAlias = Decimal | int | str
ZERO = Decimal("0")
ONE_HUNDRED = Decimal("100")


class ShoppingCartError(Exception):
    """Base exception for shopping cart errors."""


class InvalidProductNameError(ShoppingCartError):
    """Raised when a product name is empty or invalid."""


class InvalidMoneyAmountError(ShoppingCartError):
    """Raised when a monetary amount is invalid."""


class InvalidQuantityError(ShoppingCartError):
    """Raised when an item quantity is invalid."""


class CartItemNotFoundError(ShoppingCartError):
    """Raised when an item does not exist in the cart."""


class UnitPriceMismatchError(ShoppingCartError):
    """Raised when an existing item is added with a different unit price."""


class InvalidDiscountError(ShoppingCartError):
    """Raised when a discount value is invalid."""


@dataclass(frozen=True, slots=True)
class CartItem:
    """Represents a single product line item in a shopping cart."""

    product_name: str
    unit_price: Decimal
    quantity: int

    def __post_init__(self) -> None:
        normalized_product_name = _normalize_product_name(self.product_name)
        _validate_unit_price(self.unit_price)
        _validate_quantity(self.quantity)

        object.__setattr__(self, "product_name", normalized_product_name)

    @property
    def line_total(self) -> Decimal:
        """Return the total price for this cart item."""
        return self.unit_price * self.quantity

    def with_quantity(self, quantity: int) -> CartItem:
        """Return a copy of this item with an updated quantity."""
        _validate_quantity(quantity)
        return replace(self, quantity=quantity)


class Discount(Protocol):
    """Defines the interface for cart discount strategies."""

    def calculate_discount(self, subtotal: Decimal) -> Decimal:
        """Calculate the discount amount for a subtotal."""


@dataclass(frozen=True, slots=True)
class PercentageDiscount:
    """Represents a percentage-based discount."""

    percentage: Decimal

    def __post_init__(self) -> None:
        if self.percentage < ZERO or self.percentage > ONE_HUNDRED:
            raise InvalidDiscountError(
                f"Percentage discount must be between 0 and 100 inclusive; "
                f"received {self.percentage}."
            )

    def calculate_discount(self, subtotal: Decimal) -> Decimal:
        """Calculate the percentage discount for a subtotal."""
        return subtotal * (self.percentage / ONE_HUNDRED)


@dataclass(frozen=True, slots=True)
class FlatDiscount:
    """Represents a fixed-amount discount."""

    amount: Decimal

    def __post_init__(self) -> None:
        if self.amount < ZERO:
            raise InvalidDiscountError(
                f"Flat discount cannot be negative; received {self.amount}."
            )

    def calculate_discount(self, subtotal: Decimal) -> Decimal:
        """Calculate the flat discount for a subtotal."""
        return min(self.amount, subtotal)


class ShoppingCart:
    """Manages cart items, discounts, and total calculations."""

    def __init__(self) -> None:
        self._items: dict[str, CartItem] = {}
        self._discount: Discount | None = None

    def add_item(
        self,
        product_name: str,
        unit_price: MoneyInput,
        quantity: int = 1,
    ) -> None:
        """Add an item to the cart or increase its quantity if it already exists."""
        normalized_product_name = _normalize_product_name(product_name)
        normalized_unit_price = _normalize_money_amount(unit_price, "unit price")
        _validate_unit_price(normalized_unit_price)
        _validate_quantity(quantity)

        existing_item = self._items.get(normalized_product_name)

        if existing_item is not None:
            if existing_item.unit_price != normalized_unit_price:
                raise UnitPriceMismatchError(
                    f"Product '{normalized_product_name}' already exists with unit "
                    f"price {existing_item.unit_price}; received {normalized_unit_price}."
                )

            updated_quantity = existing_item.quantity + quantity
            self._items[normalized_product_name] = existing_item.with_quantity(
                updated_quantity
            )
            return

        self._items[normalized_product_name] = CartItem(
            product_name=normalized_product_name,
            unit_price=normalized_unit_price,
            quantity=quantity,
        )

    def remove_item(self, product_name: str) -> None:
        """Remove an item from the cart by product name."""
        normalized_product_name = _normalize_product_name(product_name)
        self._get_item_or_raise(normalized_product_name)
        del self._items[normalized_product_name]

    def update_quantity(self, product_name: str, quantity: int) -> None:
        """Update the quantity of an existing cart item."""
        normalized_product_name = _normalize_product_name(product_name)
        existing_item = self._get_item_or_raise(normalized_product_name)
        self._items[normalized_product_name] = existing_item.with_quantity(quantity)

    def calculate_subtotal(self) -> Decimal:
        """Calculate the cart subtotal before discounts."""
        return sum((item.line_total for item in self._items.values()), ZERO)

    def apply_percentage_discount(self, percentage: MoneyInput) -> None:
        """Apply a percentage discount to the cart."""
        normalized_percentage = _normalize_money_amount(percentage, "percentage discount")
        self._discount = PercentageDiscount(normalized_percentage)

    def apply_flat_discount(self, amount: MoneyInput) -> None:
        """Apply a flat discount to the cart."""
        normalized_amount = _normalize_money_amount(amount, "flat discount")
        self._discount = FlatDiscount(normalized_amount)

    def clear_discount(self) -> None:
        """Remove any active discount from the cart."""
        self._discount = None

    def calculate_total(self) -> Decimal:
        """Calculate the cart total after applying the active discount."""
        subtotal = self.calculate_subtotal()
        discount_amount = self._calculate_discount_amount(subtotal)
        return subtotal - discount_amount

    def list_items(self) -> tuple[CartItem, ...]:
        """Return all cart items as an immutable collection."""
        return tuple(self._items.values())

    def clear(self) -> None:
        """Remove all items and discounts from the cart."""
        self._items.clear()
        self._discount = None

    def _get_item_or_raise(self, product_name: str) -> CartItem:
        if product_name not in self._items:
            raise CartItemNotFoundError(
                f"Product '{product_name}' does not exist in the cart."
            )

        return self._items[product_name]

    def _calculate_discount_amount(self, subtotal: Decimal) -> Decimal:
        if self._discount is None:
            return ZERO

        return min(self._discount.calculate_discount(subtotal), subtotal)


def _normalize_product_name(product_name: str) -> str:
    if not isinstance(product_name, str):
        raise InvalidProductNameError(
            f"Product name must be a string; received {type(product_name).__name__}."
        )

    normalized_product_name = product_name.strip()

    if not normalized_product_name:
        raise InvalidProductNameError("Product name cannot be empty or whitespace.")

    return normalized_product_name


def _normalize_money_amount(amount: MoneyInput, field_name: str) -> Decimal:
    if isinstance(amount, bool):
        raise InvalidMoneyAmountError(f"{field_name} cannot be a boolean value.")

    if isinstance(amount, float):
        raise InvalidMoneyAmountError(
            f"{field_name} cannot be a float; use Decimal or a string instead."
        )

    try:
        decimal_amount = amount if isinstance(amount, Decimal) else Decimal(str(amount))
    except (InvalidOperation, ValueError) as error:
        raise InvalidMoneyAmountError(
            f"{field_name} must be a valid decimal amount; received {amount!r}."
        ) from error

    if not decimal_amount.is_finite():
        raise InvalidMoneyAmountError(
            f"{field_name} must be finite; received {decimal_amount}."
        )

    return decimal_amount


def _validate_unit_price(unit_price: Decimal) -> None:
    if unit_price <= ZERO:
        raise InvalidMoneyAmountError(
            f"Unit price must be greater than zero; received {unit_price}."
        )


def _validate_quantity(quantity: int) -> None:
    if isinstance(quantity, bool) or not isinstance(quantity, int):
        raise InvalidQuantityError(
            f"Quantity must be an integer; received {type(quantity).__name__}."
        )

    if quantity <= 0:
        raise InvalidQuantityError(
            f"Quantity must be greater than zero; received {quantity}."
        )
